import React, { useState, useRef } from 'react';
import { Shield, HardHat, Footprints, Eye, Smartphone, Activity, Zap, AlertTriangle, CheckCircle } from 'lucide-react';

interface DetectionClass {
  id: string;
  label: string;
  enabled: boolean;
  icon: React.ReactNode;
}

const SafetyDashboard: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement | null>(null);
  const [isStreaming, setIsStreaming] = useState(false);
  const [safetyScore, setSafetyScore] = useState(85); // Example score

  const [classes, setClasses] = useState<DetectionClass[]>([
    { id: 'helmet', label: 'Helmet', enabled: true, icon: <HardHat size={18} /> },
    { id: 'boots', label: 'Boots', enabled: true, icon: <Footprints size={18} /> },
    { id: 'glasses', label: 'Safety Glasses', enabled: false, icon: <Eye size={18} /> },
    { id: 'gloves', label: 'Gloves', enabled: false, icon: <Zap size={18} /> },
    { id: 'vest', label: 'Safety Vest', enabled: true, icon: <Shield size={18} /> },
    { id: 'phones', label: 'Phones', enabled: false, icon: <Smartphone size={18} /> },
  ]);

  const toggleClass = (id: string) => {
    setClasses(prev => prev.map(c => c.id === id ? { ...c, enabled: !c.enabled } : c));
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-[#e0e0e0] flex items-center justify-center p-4 font-sans">
      <div className="w-full max-w-7xl bg-[#141414] border border-[#333] rounded-xl shadow-2xl flex flex-col md:flex-row overflow-hidden min-h-[700px]">
        
        {/* LEFT SIDEBAR: Detection Filters */}
        <aside className="w-full md:w-56 border-r border-[#333] p-5 bg-[#0f0f0f]">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-gray-500 mb-6">
            YOLO Filters
          </h2>
          <div className="space-y-2">
            {classes.map((item) => (
              <div key={item.id} className="flex items-center justify-between bg-[#1a1a1a] p-3 rounded-lg border border-[#222] hover:border-[#444] transition-colors">
                <div className="flex items-center gap-3">
                  <span className={item.enabled ? "text-green-500" : "text-gray-600"}>{item.icon}</span>
                  <span className="text-xs font-semibold">{item.label}</span>
                </div>
                <button
                  onClick={() => toggleClass(item.id)}
                  className={`relative inline-flex h-4 w-8 items-center rounded-full transition-colors ${
                    item.enabled ? 'bg-green-500' : 'bg-gray-700'
                  }`}
                >
                  <span className={`h-2 w-2 transform rounded-full bg-white transition-transform ${item.enabled ? 'translate-x-5' : 'translate-x-1'}`} />
                </button>
              </div>
            ))}
          </div>
        </aside>

        {/* CENTER: Main Feed */}
        <main className="flex-1 p-6 flex flex-col bg-[#111]">
          <header className="flex justify-between items-center mb-4 border-b border-[#333] pb-4">
            <div className="flex items-center gap-2">
              <div className={`h-2 w-2 rounded-full ${isStreaming ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`} />
              <span className="text-xs font-bold tracking-widest uppercase">Cam_01 // Site_Floor</span>
            </div>
          </header>

          <div className="relative aspect-video bg-black rounded-lg border border-[#333] overflow-hidden">
            <video ref={videoRef} autoPlay playsInline className={`w-full h-full object-cover ${isStreaming ? 'opacity-100' : 'opacity-0'}`} />
            {!isStreaming && (
              <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-700 uppercase text-[10px] tracking-widest gap-2">
                <Activity size={32} className="opacity-20" />
                Signal Offline
              </div>
            )}
          </div>

          <div className="grid grid-cols-2 gap-3 mt-6">
            <button onClick={() => setIsStreaming(true)} className="bg-green-600/10 border border-green-500/50 text-green-500 py-3 rounded text-[10px] font-bold uppercase hover:bg-green-500 hover:text-black transition-all">Initiate Feed</button>
            <button onClick={() => setIsStreaming(false)} className="bg-red-900/10 border border-red-500/50 text-red-500 py-3 rounded text-[10px] font-bold uppercase hover:bg-red-600 hover:text-white transition-all">Abort Stream</button>
          </div>
        </main>

        {/* RIGHT SIDEBAR: Safety Score */}
        <aside className="w-full md:w-64 border-l border-[#333] p-5 bg-[#0f0f0f]">
          <h2 className="text-[10px] font-bold uppercase tracking-[0.2em] text-gray-500 mb-6 text-right">
            Safety Metrics
          </h2>

          {/* Gauge Section */}
          <div className="flex flex-col items-center py-6 border-b border-[#222]">
            <div className="relative flex items-center justify-center">
                {/* Visual Circle Gauge */}
              <svg className="w-32 h-32">
                <circle className="text-[#222]" strokeWidth="8" stroke="currentColor" fill="transparent" r="50" cx="64" cy="64" />
                <circle 
                  className={safetyScore > 70 ? "text-green-500" : "text-yellow-500"} 
                  strokeWidth="8" 
                  strokeDasharray={314} 
                  strokeDashoffset={314 - (314 * safetyScore) / 100} 
                  strokeLinecap="round" 
                  stroke="currentColor" 
                  fill="transparent" 
                  r="50" cx="64" cy="64" 
                />
              </svg>
              <div className="absolute flex flex-col items-center">
                <span className="text-2xl font-black">{safetyScore}%</span>
                <span className="text-[8px] text-gray-500 uppercase">Integrity</span>
              </div>
            </div>
          </div>

          {/* Status List */}
          <div className="mt-6 space-y-4">
            <div className="flex items-start gap-3">
              <CheckCircle className="text-green-500 mt-1" size={16} />
              <div>
                <p className="text-[11px] font-bold uppercase">Zone Secure</p>
                <p className="text-[10px] text-gray-500">All PPE identified on 4/4 subjects.</p>
              </div>
            </div>
            <div className="flex items-start gap-3 opacity-50">
              <AlertTriangle className="text-yellow-500 mt-1" size={16} />
              <div>
                <p className="text-[11px] font-bold uppercase">Minor Alert</p>
                <p className="text-[10px] text-gray-500">Subject B: Unverified Footwear.</p>
              </div>
            </div>
          </div>

          <div className="mt-auto pt-10">
            <div className="bg-[#1a1a1a] p-3 rounded border border-[#333] text-center">
                <p className="text-[9px] text-gray-500 uppercase mb-1">Risk Level</p>
                <p className="text-xs font-bold text-green-400">NOMINAL</p>
            </div>
          </div>
        </aside>

      </div>
    </div>
  );
};

export default SafetyDashboard;